'use strict';

// Duration parser. See docs/timeouts.md for the contract and
// docs/conventions.md for the format rules (compound segments sum, ms is
// tokenized before m, a bare integer is milliseconds, the whole string must
// be consumed).
//
// Returns a non-negative integer number of milliseconds; throws on an
// unparseable input. Pure: no mutation, no I/O.
const UNITS = { ms: 1, s: 1000, m: 60_000, h: 3_600_000, d: 86_400_000 };
// ms must appear before m in the alternation so "500ms" doesn't tokenize as 500m + s
const SEGMENT_RE = /(\d+)(ms|s|m|h|d)/g;

function parseDuration(str) {
  if (typeof str !== 'string' || str.length === 0) {
    throw new Error(`parseDuration: invalid input: ${JSON.stringify(str)}`);
  }

  // Bare integer → milliseconds
  if (/^\d+$/.test(str)) {
    return parseInt(str, 10);
  }

  SEGMENT_RE.lastIndex = 0;
  let total = 0;
  let consumed = 0;
  let match;

  while ((match = SEGMENT_RE.exec(str)) !== null) {
    if (match.index !== consumed) {
      throw new Error(`parseDuration: unexpected characters near position ${consumed} in "${str}"`);
    }
    total += parseInt(match[1], 10) * UNITS[match[2]];
    consumed += match[0].length;
  }

  if (consumed === 0 || consumed !== str.length) {
    throw new Error(`parseDuration: unparseable input: "${str}"`);
  }

  return total;
}

module.exports = { parseDuration };

