const { parseDuration } = require('./src/core/duration.js');
const tests = [
  ['30s',    30000],
  ['5m',     300000],
  ['1000ms', 1000],
  ['2h',     7200000],
  ['1h30m',  5400000],
  ['500ms',  500],
