  ['1d',     86400000],
  ['1h30m15s', 5415000],
];
let pass = 0, fail = 0;
for (const [input, expected] of tests) {
  const got = parseDuration(input);
  if (got === expected) { console.log('PASS', input, '->', got); pass++; }
  else { console.log('FAIL', input, '-> got', got, 'expected', expected); fail++; }
}
// Error cases
for (const bad of ['', 'abc', '1x', '1h abc', null]) {
  try { parseDuration(bad); console.log('FAIL should throw for', JSON.stringify(bad)); fail++; }
  catch (e) { console.log('PASS throws for', JSON.stringify(bad)); pass++; }
}
console.log(pass + ' passed, ' + fail + ' failed');
